def parse_users(filename):
    valid_users = {}

    with open(filename, 'r') as f:
        for line in f:
            line = line.strip()
            if not line:
                continue

            parts = line.split()
            if len(parts) != 2:
                continue

            name, age_str = parts

            try:
                age = int(age_str)
            except ValueError:
                continue

            if age <= 0:
                continue

            # Check name is valid (alphabetic)
            if not name.isalpha():
                continue

            # Handle uniqueness: if name appears more than once, it's not unique
            if name in valid_users:
                valid_users[name] = None  # Mark as duplicate
            else:
                valid_users[name] = age

    # Filter out duplicates
    unique_users = {name: age for name, age in valid_users.items() if age is not None}

    if not unique_users:
        print("No valid unique users found.")
        return

    oldest_name = max(unique_users, key=lambda n: unique_users[n])
    oldest_age = unique_users[oldest_name]

    print(f"{oldest_name} {oldest_age}")

parse_users("users.txt")
